import dashboardStyle from "./dashboardStyle";

const LOGO_URI = "data:image/jpeg;base64,";

export function renderDashboardPage(): string {
  return `<!doctype html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <title>Partner Webhook Dashboard</title>
    <style>${dashboardStyle}
      .topbar { display:flex; align-items:center; justify-content:space-between; gap:16px; margin-bottom:20px; }
      .topbar-left { display:flex; align-items:center; gap:12px; }
      .topbar-logo { width:36px; height:36px; border-radius:8px; object-fit:cover; }
      .topbar-name { font-size:17px; font-weight:700; letter-spacing:-0.02em; }
      .admin-badge { padding:4px 12px; border-radius:999px; font-size:12px; font-weight:700; color:var(--warning); border:1px solid rgba(251,191,36,0.3); background:rgba(251,191,36,0.08); }
      .topbar-link { color:var(--accent); text-decoration:none; font-size:13px; font-weight:600; padding:7px 14px; border:1px solid var(--border); border-radius:999px; background:rgba(125,211,252,0.07); }
      .topbar-link:hover { background:rgba(125,211,252,0.14); }
    </style>
  </head>
  <body>
    <div class="shell">
      <div class="topbar">
        <div class="topbar-left">
          <span class="topbar-name">Grubtech</span>
          <span class="admin-badge">Admin</span>
        </div>
        <a class="topbar-link" href="/apply" target="_blank">View application page ↗</a>
      </div>
      <section class="hero">
        <div class="panel hero-main">
          <div class="eyebrow">Partner webhook control room <b style="color: #fbbf24;"> by sayed ehab </b></div>
          <h1>Route applications, inspect JSON, and watch the countries roll in.</h1>
          <div class="hero-meta">
            <div class="pill"><span class="dot" id="deliveryDot"></span><span id="deliveryLabel">Loading...</span></div>
            <div class="pill" id="processedPill">0 processed</div>
            <div class="pill" id="routePill">0 routed</div>
            <div class="pill" id="countryPill">0 countries</div>
          </div>
        </div>
        <aside class="panel side">
          <div class="toggle-card">
            <div class="toggle-row">
              <div class="toggle-copy">
                <h2>Discord delivery</h2>
                <div class="muted">Turn live posting on or off. When off, submissions stay in dry-run mode.</div>
              </div>
              <label class="switch" aria-label="toggle delivery"><input id="deliveryToggle" type="checkbox" /><span class="slider"></span></label>
            </div>
          </div>
          <div class="form-card">
            <h2>Send a test payload</h2>
            <div class="muted">Push a synthetic JSON payload through the webhook pipeline for testing.</div>
            <form id="sampleForm">
              <div class="form-grid">
                <label>Application ID<input name="application_id" value="demo-" /></label>
                <label>Business name<input name="business_name" value="Demo Commerce" /></label>
                <label>Contact email<input name="contact_email" value="demo@example.com" /></label>
                <label>Monthly orders<input name="monthly_orders" type="number" min="0" value="1200" /></label>
                <label>Country<input name="country_raw" value="UAE" /></label>
                <label>Phone<input name="phone" value="+971501234567" /></label>
                <label class="span-2">Submitted at<input name="submitted_at" id="submittedAtInput" /></label>
                <label class="span-2">Email body<textarea name="body_text">Hello, this is a sample partner application.</textarea></label>
              </div>
              <div class="actions">
                <button class="button" type="submit">Send test payload</button>
                <button class="button secondary" type="button" id="refreshButton">Refresh</button>
              </div>
            </form>
            <div class="footer-note">Sends to <code>/webhook/partner-application</code> — same pipeline as production.</div>
          </div>
        </aside>
      </section>
      <section class="grid" id="statsGrid"></section>
      <section class="content-grid">
        <div class="panel section">
          <div class="section-head"><h2>Countries</h2><div class="muted">Count by resolved country</div></div>
          <div class="bars" id="countriesList"></div>
        </div>
        <div>
          <div class="panel section">
            <div class="section-head"><h2>Routes</h2><div class="muted">Where each submission was sent</div></div>
            <div class="bars" id="routesList"></div>
          </div>
          <div class="panel section">
            <div class="section-head"><h2>Recent JSON</h2><div class="muted">Click a card to inspect</div></div>
            <div class="recent-grid" id="recentList"></div>
            <div class="json-panel">
              <div class="json-header"><span>Selected record</span><span id="jsonMeta">Waiting for data...</span></div>
              <pre id="jsonView">{}</pre>
            </div>
          </div>
        </div>
      </section>
    </div>
    <script>
      const state = { selected: null };
      const deliveryToggle = document.getElementById('deliveryToggle');
      const deliveryLabel  = document.getElementById('deliveryLabel');
      const deliveryDot    = document.getElementById('deliveryDot');
      const processedPill  = document.getElementById('processedPill');
      const routePill      = document.getElementById('routePill');
      const countryPill    = document.getElementById('countryPill');
      const statsGrid      = document.getElementById('statsGrid');
      const countriesList  = document.getElementById('countriesList');
      const routesList     = document.getElementById('routesList');
      const recentList     = document.getElementById('recentList');
      const jsonView       = document.getElementById('jsonView');
      const jsonMeta       = document.getElementById('jsonMeta');
      const submittedAtInput = document.getElementById('submittedAtInput');
      const refreshButton  = document.getElementById('refreshButton');
      const sampleForm     = document.getElementById('sampleForm');
      submittedAtInput.value = new Date().toISOString();

      function fmt(v) { return new Intl.NumberFormat().format(v); }
      function esc(v) { return String(v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;'); }

      function renderStats(data) {
        const items = [
          ['Processed', data.totals.processed, 'All stored records'],
          ['Delivered', data.totals.delivered, 'Live Discord posts sent'],
          ['Dry runs', data.totals.dry_runs, 'Delivery was off'],
          ['Failed', data.totals.failed_notifications, 'Webhook failed after retries'],
        ];
        statsGrid.innerHTML = items.map(([l,v,f]) =>
          '<article class="panel stat"><div class="stat-label">'+esc(l)+'</div><div class="stat-value">'+fmt(v)+'</div><div class="stat-foot">'+esc(f)+'</div></article>'
        ).join('');
      }

      function renderBars(container, items) {
        const max = Math.max(...items.map(i => i.count), 1);
        container.innerHTML = items.length
          ? items.map(i => '<div class="bar-row"><div class="bar-label">'+esc(i.label)+'</div><div class="bar-track"><div class="bar-fill" style="width:'+Math.max(6,Math.round(i.count/max*100))+'%"></div></div><div class="bar-count">'+fmt(i.count)+'</div></div>').join('')
          : '<div class="muted">No data yet.</div>';
      }

      function renderRecent(recent) {
        recentList.innerHTML = recent.length
          ? recent.map((r,i) => {
              const dupTag = r.duplicate ? '<span class="tag review" style="margin-left:6px;font-size:11px;">dup</span>' : '';
              return '<article class="recent-card" data-index="'+i+'"><div class="recent-top"><div><div class="recent-title">'+esc(r.business_name)+dupTag+'</div><div class="muted">'+esc(r.country?.name||r.country?.raw||'Unresolved')+'</div></div><span class="tag '+esc(r.routing.destination)+'">'+esc(r.routing.destination)+'</span></div><div class="muted" style="margin-top:10px;">'+esc(r.application_id)+' · '+esc(r.processed_at)+'</div></article>';
            }).join('')
          : '<div class="muted">No submissions yet.</div>';
        recentList.querySelectorAll('.recent-card').forEach(card => {
          card.addEventListener('click', () => {
            const r = recent[Number(card.dataset.index)];
            if (!r) return;
            state.selected = r;
            jsonView.textContent = JSON.stringify(r, null, 2);
            jsonMeta.textContent = r.application_id;
          });
        });
        if (!state.selected && recent[0]) {
          state.selected = recent[0];
          jsonView.textContent = JSON.stringify(recent[0], null, 2);
          jsonMeta.textContent = recent[0].application_id;
        }
      }

      function syncHeader(data) {
        const on = data.delivery_enabled;
        deliveryToggle.checked = on;
        deliveryLabel.textContent = on ? 'Live delivery enabled' : 'Dry run mode';
        deliveryDot.style.background = on ? 'var(--success)' : 'var(--warning)';
        deliveryDot.style.boxShadow  = on ? '0 0 0 4px rgba(52,211,153,0.18)' : '0 0 0 4px rgba(251,191,36,0.16)';
        processedPill.textContent = fmt(data.totals.processed)+' processed';
        routePill.textContent     = fmt(data.routes.reduce((s,i)=>s+i.count,0))+' routed';
        countryPill.textContent   = fmt(data.countries.length)+' countries';
      }

      async function loadDashboard() {
        const res  = await fetch('/api/dashboard');
        const data = await res.json();
        syncHeader(data);
        renderStats(data);
        renderBars(countriesList, data.countries);
        renderBars(routesList,    data.routes);
        renderRecent(data.recent);
      }

      deliveryToggle.addEventListener('change', async (e) => {
        try {
          await fetch('/api/settings/delivery', {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({enabled:e.target.checked})});
          await loadDashboard();
        } catch(err) { console.error(err); e.target.checked = !e.target.checked; }
      });

      refreshButton.addEventListener('click', () => loadDashboard().catch(console.error));

      sampleForm.addEventListener('submit', async (e) => {
        e.preventDefault();
        const fd = new FormData(sampleForm);
        const p  = Object.fromEntries(fd.entries());
        const body = {
          application_id: String(p.application_id||'demo')+'-'+Date.now(),
          business_name:  String(p.business_name||'Demo Commerce'),
          contact_email:  String(p.contact_email||'demo@example.com'),
          body:           String(p.body_text||''),
          country:        String(p.country_raw||'UAE'),
          phone:          String(p.phone||''),
          monthly_orders: Number(p.monthly_orders||0),
          submitted_at:   String(p.submitted_at||new Date().toISOString()),
        };
        const res  = await fetch('/webhook/partner-application',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)});
        const json = await res.json();
        state.selected = json;
        jsonView.textContent = JSON.stringify(json,null,2);
        jsonMeta.textContent = res.ok ? body.application_id : 'request failed';
        await loadDashboard();
      });

      loadDashboard().catch(err => {
        console.error(err);
        jsonView.textContent = JSON.stringify({error:'Failed to load dashboard.'},null,2);
        jsonMeta.textContent = 'error';
      });
    </script>
  </body>
</html>`;
}
